package org.apache.commons.jxpath.ri.compiler;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.jxpath.ri.compiler.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.jxpath.ri.compiler.steps;

import io.cucumber.java.en.*;
import org.apache.commons.jxpath.JXPathContext;
import static org.junit.Assert.*;

public class StepDefs {

    private JXPathContext context;
    private Object result;

    @Given("a variable \"d\" is defined as a String array containing \"a\" and \"b\"")
    public void defineStringArrayVariable() {
        String[] array = {"a", "b"};
        context = JXPathContext.newContext(new Object());
        context.getVariables().declareVariable("d", array);
    }

    @When("the XPath expression \"(.*)\" is evaluated")
    public void evaluateXPathExpression(String expression) {
        try {
            result = context.getValue(expression);
        } catch (Exception e) {
            // Store the exception if needed for verification
            result = e;
        }
    }

    @Then("the result should be Boolean true")
    public void verifyResultIsTrue() {
        assertNotNull("Result should not be null", result);
        assertTrue("Result should be a boolean and true", 
                  result instanceof Boolean && ((Boolean) result).booleanValue());
    }

    @Then("the result should be Boolean false")
    public void verifyResultIsFalse() {
        assertNotNull("Result should not be null", result);
        assertTrue("Result should be a boolean and false", 
                  result instanceof Boolean && !((Boolean) result).booleanValue());
    }
}

